1	const getCell = (grid: boolean[][], r: number, c: number): boolean => {
2	  if (r < 0 || r >= grid.length) return false;
3	  const row = grid[r];
4	  if (c < 0 || c >= row.length) return false;
5	  return row[c] === true;
6	};
7	
8	const countNeighbors = (grid: boolean[][], r: number, c: number): number => {
9	  let neighbors = 0;
10	  for (let dr = -1; dr <= 1; dr++) {
11	    for (let dc = -1; dc <= 1; dc++) {
12	      if (dr === 0 && dc === 0) continue;
13	      if (getCell(grid, r + dr, c + dc)) neighbors++;
14	    }
15	  }
16	  return neighbors;
17	};
18	
19	const livesOn = (alive: boolean, neighbors: number): boolean =>
20	  alive ? neighbors === 2 || neighbors === 3 : neighbors === 3;
21	
22	export function nextGeneration(grid: boolean[][]): boolean[][] {
23	  if (grid.length === 0) return [];
24	
25	  const maxCols = Math.max(...grid.map(row => row.length));
26	
27	  return grid.map((_, r) => {
28	    const newRow: boolean[] = [];
29	    for (let c = -1; c <= maxCols; c++) {
30	      const alive = getCell(grid, r, c);
31	      const neighbors = countNeighbors(grid, r, c);
32	      if (livesOn(alive, neighbors)) {
33	        newRow.push(true);
34	      }
35	    }
36	    return newRow;
37	  });
38	}
