it("should create a new live cell when dead cell has exactly 3 live neighbors", () => {
  // L-shape: dead cell at (1,1) has exactly 3 live neighbors
  const grid = [
    [true, true],
    [true, false],
  ];
  const result = nextGeneration(grid);
  expect(result[1][1]).toBe(true);
});

